        url=d[i].attr("href")
        size=0.33;
        title = String(title).replace(/\s/g, "");
        url=baseUrl+String(url).replace(/\d+\.html$/,"")+"{{page}}.html";
        push(title,url,size)
    };

} else {

  java.toast("🤔列表刷新失败！！！");
}
JSON.stringify(result);

