@js:
var url=source.getKey(),
web=java.webView(null,url,null),
j=org.jsoup.Jsoup.parse(web),
f=j.select("form"),
a=f.attr("action"),
p=f.select("input");
var list=[];
for(i in p){
	name=p[i].attr("name")
	value=p[i].attr("value")
	clas=p[i].attr("class")
	if(value!=""){
		add=`${name}=${value}`
		}else if(clas=="text"){
			k=java.encodeURI(key,"gbk")
			add=`${name}=${k}`
			}
			list.push(add)
	}
	so=list.join("&")
a+"?"+so

