loginUrl:
userInfo = source.getLoginInfoMap();
account = userInfo['邮箱/手机'];
code = userInfo['验证码'];
//验证码为空则获取验证码，否则登录
if(account!=''&&code==''){
cookie.removeCookie(baseUrl);
java.ajax(baseUrl+'/login,{"webView": true}');
  cookies = String(cookie.getCookie(baseUrl));
  //匹配跨域token
  token = cookies.match(/XSRF-TOKEN=(.*?);/)[1];
  //@区分邮箱跟手机号
  if(account.includes('@')){
  	//请求api需要header有完整的cookie跟跨域token
    res = java.post('https://m.doufu.me/api/emailLoginCode','email='+account,{'x-csrf-token':token,'cookie':cookies});
  }else{
    res = java.post('https://m.doufu.me/api/mobileLoginCode','country_code=86&mobile='+account,{'x-csrf-token':token,'cookie':cookies});
  }
  if (res.statusCode() == 200){
  	//发送太多次验证码会导致status变成1
    throw JSON.parse(String(res.body())).status?'验证码发送失败':'验证码发送成功'
  }else{
    throw '验证码发送失败'
  }
}else{
  cookies = String(cookie.getCookie('https://m.doufu.me'));
  token = cookies.match(/XSRF-TOKEN=(.*?);/)[1];
  if(account.includes('@')){
    res = java.post('https://m.doufu.me/api/emailLoginByCode','email='+account+'&code='+code,{'x-csrf-token':token,'cookie':cookies});
  }else{
    res = java.post('https://m.doufu.me/api/mobileLoginByCode','country_code=86&mobile='+account+'&code='+code,{'x-csrf-token':token,'cookie':cookies});
  }
  if (res.statusCode() == 200){
    if (!String(res.cookies()).includes('uid')) throw '登录失败,请重新获取验证码';
    //拼接完整cookie
    header = {
      'Cookie':String(cookie.getCookie('https://m.doufu.me'))+String(res.cookies()).replace(/,/g,';').replace('{',';').replace('}',''),
      'x-csrf-token':token
    }
    headers = JSON.stringify(header)
    //cookie有效期20年，只需要登录1次
    source.putLoginHeader(headers)
  }else{
    throw '登录失败'
  }
}

