ruleSearch.bookList:
dd[:1]<js>
result.toArray().map(el=>{
    var url=String(el.select('a').attr('href')).replace(/^/,'https://www.fsxs8.com');
    var J=org.jsoup.Jsoup.parse(java.ajax(url));
    var og=selector=>String(J.select('[property="og:'+selector+'"]').attr('content'));
    return{
        name:og('novel:book_name'),
        author:og('novel:author'),
        kind:og('novel:category').replace(/小说/,'')+','+og('novel:status').replace(/中|已/,'')+','+og('novel:update_time').replace(/\s.*/,''),
        latest:og('novel:latest_chapter_name'),
        intro:og('description'),
        cover:og('image'),
        url:url,
    };
});
</js>
